      b: string;
      c: Obj1;
    }
    return {build: () => createValidate<Obj2>(), buildErrors: () => noErrs(createGetValidationErrors<Obj2>())};
  })()

c(
    Type.Object({
      b: Type.String(),
      c: Type.Intersect([Type.Object({a: Type.String()}), Type.Record(Type.String(), Type.String())]),
    })
  )

